msg.method  = 'GET';
msg.headers = { 'x-webhook-secret': env.get('NODERED_WEBHOOK_SECRET') };
msg.url     = env.get('APP_URL') + '/api/webhooks/nodered';
return msg;

const ok = msg.payload && msg.payload.ok === true;
if (ok) {
  node.status({ fill: 'green', shape: 'dot', text: '✅ Terhubung: ' + (msg.payload.service || 'FitFlow') });
  msg.result = '✅ Koneksi FitFlow OK\n' + JSON.stringify(msg.payload, null, 2);
} else {
  node.status({ fill: 'red', shape: 'dot', text: '❌ Gagal (status ' + msg.statusCode + ')' });
  msg.result = '❌ Koneksi gagal (HTTP ' + msg.statusCode + ')\n\nPastikan:\n- APP_URL sudah benar\n- NODERED_WEBHOOK_SECRET sama dengan env Vercel\n- App sudah deploy dan bisa diakses';
}
msg.payload = msg.result;
return msg;

const FONNTE_TOKEN = env.get('FONNTE_TOKEN');
msg.method  = 'GET';
msg.headers = { 'Authorization': FONNTE_TOKEN };
msg.url     = 'https://api.fonnte.com/validate-token';
return msg;

const ok = msg.statusCode === 200 || (msg.payload && msg.payload.status !== false);
if (ok) {
  node.status({ fill: 'green', shape: 'dot', text: '✅ Token Fonnte valid' });
  msg.payload = '✅ Fonnte terhubung OK\n' + JSON.stringify(msg.payload, null, 2);
} else {
  node.status({ fill: 'red', shape: 'dot', text: '❌ Token Fonnte tidak valid' });
  msg.payload = '❌ Fonnte gagal (HTTP ' + msg.statusCode + ')\n\nPastikan FONNTE_TOKEN sudah diset dengan benar di env vars Node-RED\n\n' + JSON.stringify(msg.payload, null, 2);
}
return msg;

const FONNTE_TOKEN = env.get('FONNTE_TOKEN');
const TARGET_PHONE = env.get('FITFLOW_INSTRUCTOR_PHONE'); // kirim ke nomor instruktur

msg.method  = 'POST';
msg.headers = { 'Authorization': FONNTE_TOKEN, 'Content-Type': 'application/json' };
msg.url     = 'https://api.fonnte.com/send';
msg.payload = JSON.stringify({
  target:      TARGET_PHONE,
  message:     '🧪 *Test FitFlow Node-RED*\n\nKoneksi Node-RED → Fonnte berhasil! ✅\n\nWaktu: ' + new Date().toLocaleString('id-ID'),
  countryCode: '62'
});
return msg;

const ok = msg.payload && msg.payload.status === true;
if (ok) {
  node.status({ fill: 'green', shape: 'dot', text: '✅ WA terkirim!' });
  msg.payload = '✅ WA Test terkirim!\n\nCek nomor instruktur, harus ada pesan masuk.';
} else {
  node.status({ fill: 'red', shape: 'dot', text: '❌ Gagal kirim WA' });
  msg.payload = '❌ Gagal kirim WA\n\n' + JSON.stringify(msg.payload, null, 2);
}
return msg;

